function makeItFly(creature) {
  // The function doesn't check if 'creature' is a Bird class.
  // It just checks if 'creature' has a 'fly' method.
  if (typeof creature.fly === 'function') {
    creature.fly();
  }
}

// Object A: A real Bird class
class Bird {
  fly() { console.log("Flapping wings"); }
}

// Object B: A Robot
const robot = {
  fly() { console.log("Engaging thrusters"); }
};

**Example (TypeScript):**
```typescript
// We explicitly define that 'creature' must be an object with a 'fly' method
function makeItFly(creature: { fly: () => void }) {
  creature.fly();
}

// This works
const bird = { fly: () => console.log("Flapping") };
makeItFly(bird);

// This causes a COMPILE ERROR
const rock = { weight: 5 };
makeItFly(rock); // Error: Property 'fly' does not exist on type '{ weight: number; }'
